import React, { useEffect, useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { studentsAPI } from '../../services/api';
import Card from '../../components/common/Card';
import Modal from '../../components/common/Modal';
import toast from 'react-hot-toast';
import { User, Camera, Save, Loader2, Edit3, X, GraduationCap, Users, Briefcase, MapPin, Phone, Mail } from 'lucide-react';

const StudentProfile = () => {
  const { user } = useAuth();
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [editMode, setEditMode] = useState(false);
  const [formData, setFormData] = useState({});

  useEffect(() => {
    fetchProfile();
  }, []);

  const fetchProfile = async () => {
    try {
      // Get student profile by user_id (from JWT token)
      const response = await studentsAPI.getByUserId(user.id);
      if (response.data.success) {
        setProfile(response.data.student);
        setFormData(response.data.student);
      }
    } catch (error) {
      console.error('Error fetching profile:', error);
      toast.error('Failed to load profile');
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      await studentsAPI.update(profile.id, formData);
      toast.success('Profile updated successfully');
      setEditMode(false);
      fetchProfile();
    } catch (error) {
      toast.error('Failed to update profile');
    } finally {
      setSaving(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-20">
        <Loader2 className="w-10 h-10 animate-spin text-green-600" />
      </div>
    );
  }

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Header */}
      <div className="bg-gradient-to-r from-green-600 via-green-700 to-green-800 rounded-2xl p-6 text-white relative overflow-hidden">
        <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -translate-y-1/2 translate-x-1/2"></div>
        <div className="relative z-10 flex items-center justify-between">
          <div className="flex items-center gap-4">
            <div className="w-20 h-20 bg-white/20 rounded-full flex items-center justify-center backdrop-blur-sm overflow-hidden">
              {profile?.profile_picture ? (
                <img
                  src={profile.profile_picture}
                  alt="Profile"
                  className="w-full h-full object-cover"
                />
              ) : (
                <User className="w-10 h-10 text-white" />
              )}
            </div>
            <div>
              <div className="flex items-center gap-2 text-green-200 mb-1">
                <User className="w-4 h-4" />
                <span className="text-sm font-medium">Student Profile</span>
              </div>
              <h1 className="text-2xl font-bold">{profile?.first_name} {profile?.last_name}</h1>
              <p className="text-green-100 text-sm">{profile?.student_id} | {profile?.year_level} - {profile?.section}</p>
            </div>
          </div>
          <button
            onClick={() => setEditMode(!editMode)}
            className={`px-4 py-2 rounded-lg font-medium transition-colors flex items-center gap-2 ${
              editMode
                ? 'bg-white/20 text-white hover:bg-white/30'
                : 'bg-white text-green-600 hover:bg-green-50'
            }`}
          >
            {editMode ? <X className="w-4 h-4" /> : <Edit3 className="w-4 h-4" />}
            {editMode ? 'Cancel' : 'Edit Profile'}
          </button>
        </div>
      </div>

      {/* Profile Form */}
      <form onSubmit={handleSubmit}>
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
          {/* Personal Information */}
          <Card title="Personal Information" icon={User} className="lg:col-span-2">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="label">First Name</label>
                <input
                  type="text"
                  name="first_name"
                  value={formData.first_name || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50 disabled:text-secondary-600"
                />
              </div>
              <div>
                <label className="label">Middle Name</label>
                <input
                  type="text"
                  name="middle_name"
                  value={formData.middle_name || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50 disabled:text-secondary-600"
                />
              </div>
              <div>
                <label className="label">Last Name</label>
                <input
                  type="text"
                  name="last_name"
                  value={formData.last_name || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50 disabled:text-secondary-600"
                />
              </div>
              <div>
                <label className="label">Gender</label>
                <select
                  name="gender"
                  value={formData.gender || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50 disabled:text-secondary-600"
                >
                  <option value="">Select Gender</option>
                  <option value="Male">Male</option>
                  <option value="Female">Female</option>
                  <option value="Other">Other</option>
                </select>
              </div>
              <div>
                <label className="label">Contact Number</label>
                <input
                  type="text"
                  name="contact_number"
                  value={formData.contact_number || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50 disabled:text-secondary-600"
                />
              </div>
              <div>
                <label className="label">Email</label>
                <input
                  type="email"
                  name="email"
                  value={formData.email || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50 disabled:text-secondary-600"
                />
              </div>
              <div className="md:col-span-2">
                <label className="label">Address</label>
                <textarea
                  name="address"
                  value={formData.address || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  rows={2}
                  className="input-field disabled:bg-secondary-50 disabled:text-secondary-600"
                />
              </div>
            </div>
          </Card>

          {/* Guardian Information */}
          <Card title="Guardian Information" icon={Users}>
            <div className="space-y-4">
              <div>
                <label className="label">Guardian Name</label>
                <input
                  type="text"
                  name="guardian_name"
                  value={formData.guardian_name || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50 disabled:text-secondary-600"
                />
              </div>
              <div>
                <label className="label">Guardian Contact</label>
                <input
                  type="text"
                  name="guardian_contact"
                  value={formData.guardian_contact || ''}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50 disabled:text-secondary-600"
                />
              </div>
            </div>
          </Card>

          {/* Academic Information */}
          <Card title="Academic Information" icon={GraduationCap}>
            <div className="space-y-4">
              <div className="p-3 bg-secondary-50 rounded-lg">
                <p className="text-xs text-secondary-500 uppercase tracking-wide">Year Level</p>
                <p className="font-medium text-secondary-800">{profile?.year_level || 'N/A'}</p>
              </div>
              <div className="p-3 bg-secondary-50 rounded-lg">
                <p className="text-xs text-secondary-500 uppercase tracking-wide">Section</p>
                <p className="font-medium text-secondary-800">{profile?.section || 'N/A'}</p>
              </div>
              <div className="p-3 bg-secondary-50 rounded-lg">
                <p className="text-xs text-secondary-500 uppercase tracking-wide">Status Record</p>
                <p className="font-medium">
                  <span className={`badge ${
                    profile?.status_record === 'Regular' ? 'badge-success' : 'badge-warning'
                  }`}>
                    {profile?.status_record || 'N/A'}
                  </span>
                </p>
              </div>
            </div>
          </Card>

          {/* Work Information */}
          <Card title="Work Information" icon={Briefcase}>
            <div className="space-y-4">
              <div>
                <label className="label">Working Student</label>
                <select
                  name="working_student"
                  value={formData.working_student || 'No'}
                  onChange={handleChange}
                  disabled={!editMode}
                  className="input-field disabled:bg-secondary-50 disabled:text-secondary-600"
                >
                  <option value="No">No</option>
                  <option value="Yes">Yes</option>
                </select>
              </div>
              {formData.working_student === 'Yes' && (
                <div>
                  <label className="label">Type of Work</label>
                  <input
                    type="text"
                    name="work_type"
                    value={formData.work_type || ''}
                    onChange={handleChange}
                    disabled={!editMode}
                    className="input-field disabled:bg-secondary-50 disabled:text-secondary-600"
                  />
                </div>
              )}
            </div>
          </Card>
        </div>

        {editMode && (
          <div className="mt-6 flex justify-end">
            <button
              type="submit"
              disabled={saving}
              className="btn-primary flex items-center gap-2"
            >
              {saving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />}
              {saving ? 'Saving...' : 'Save Changes'}
            </button>
          </div>
        )}
      </form>
    </div>
  );
};

export default StudentProfile;
